ambiguous_dsl.choice_dsl:
PREFIX : <http://ambrosia.example.org/airport#>
PREFIX p: <http://ambrosia.example.org/airport/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
CHOICE scope {
  distributive: { SELECT ?name ?capacity WHERE {
  ?airlines_fleets a :Airlines_Fleets .
  ?fleets a :Fleets .
  ?airlines_fleets p:hasFleets ?fleets .
  ?airlines a :Airlines .
  ?airlines_fleets p:hasAirlines ?airlines .
  ?airlines p:name ?name .
  ?fleets p:capacity ?capacity .
} }
  collective: { SELECT ?capacity WHERE {
  { SELECT ?child (COUNT(DISTINCT ?parent) AS ?nf) WHERE { ?l p:hasFleets ?child ; p:hasAirlines ?parent . } GROUP BY ?child }
  ?child p:capacity ?capacity .
  { SELECT (COUNT(DISTINCT ?t) AS ?total) WHERE { ?t a :Airlines } }
  FILTER(?nf = ?total)
} }
}

